{
  "parent": {
    "name": "DataPipeline",
    "purpose": "ETL data processing: ingest, transform, validate, export.",
    "call_inputs": {
      "input": "Any - JSON with action (ingest/transform/validate/export), source"
    },
    "call_outputs": {
      "output": "Any - JSON with success, records_processed, errors, data"
    }
  },
  "children": [
    {
      "name": "IngestData",
      "purpose": "Read and parse input data from source into raw_data store",
      "call_inputs": [
        {
          "name": "input",
          "description": "JSON with action and source",
          "source": "parent input"
        }
      ],
      "call_outputs": [
        {
          "name": "ingest_result",
          "description": "JSON with success status and records count",
          "consumer": "parent"
        }
      ],
      "internal_leaf_accesses": [
        {
          "store": "raw_data",
          "access": "write",
          "description": "Write parsed records to raw_data store"
        }
      ],
      "governance": {
        "execution_mode": "synchronous",
        "retry_policy": {
          "max_retries": 3,
          "backoff_seconds": 1
        },
        "timeout_seconds": 30,
        "logging_level": "info",
        "error_handling": "fail_fast"
      },
      "resources": {
        "global_vars": [
          {
            "name": "raw_data",
            "type": "memory_store",
            "access": "write",
            "description": "Store for ingested raw data"
          }
        ],
        "data_operations": [
          {
            "operation": "write",
            "target": "raw_data",
            "description": "Write parsed records to raw_data store"
          }
        ]
      }
    },
    {
      "name": "TransformData",
      "purpose": "Apply transformations to data in raw_data and write to processed_data",
      "call_inputs": [
        {
          "name": "transform_trigger",
          "description": "Signal to start transformation",
          "source": "parent input"
        }
      ],
      "call_outputs": [
        {
          "name": "transform_result",
          "description": "JSON with success status and records transformed",
          "consumer": "parent"
        }
      ],
      "internal_leaf_accesses": [
        {
          "store": "raw_data",
          "access": "read",
          "description": "Read raw data for transformation"
        },
        {
          "store": "processed_data",
          "access": "write",
          "description": "Write transformed records to processed_data store"
        }
      ],
      "governance": {
        "execution_mode": "synchronous",
        "retry_policy": {
          "max_retries": 3,
          "backoff_seconds": 1
        },
        "timeout_seconds": 60,
        "logging_level": "info",
        "error_handling": "fail_fast"
      },
      "resources": {
        "global_vars": [
          {
            "name": "raw_data",
            "type": "memory_store",
            "access": "read",
            "description": "Store for ingested raw data"
          },
          {
            "name": "processed_data",
            "type": "memory_store",
            "access": "write",
            "description": "Store for transformed data"
          }
        ],
        "data_operations": [
          {
            "operation": "read",
            "target": "raw_data",
            "description": "Read raw data for transformation"
          },
          {
            "operation": "write",
            "target": "processed_data",
            "description": "Write transformed records to processed_data store"
          }
        ]
      }
    },
    {
      "name": "ValidateQuality",
      "purpose": "Check quality of transformed data and mark valid/invalid records",
      "call_inputs": [
        {
          "name": "validate_trigger",
          "description": "Signal to start validation",
          "source": "parent input"
        }
      ],
      "call_outputs": [
        {
          "name": "validate_result",
          "description": "JSON with success status, valid count, invalid count",
          "consumer": "parent"
        }
      ],
      "internal_leaf_accesses": [
        {
          "store": "processed_data",
          "access": "read_write",
          "description": "Read processed data, update with validity flags"
        }
      ],
      "governance": {
        "execution_mode": "synchronous",
        "retry_policy": {
          "max_retries": 3,
          "backoff_seconds": 1
        },
        "timeout_seconds": 60,
        "logging_level": "info",
        "error_handling": "fail_fast"
      },
      "resources": {
        "global_vars": [
          {
            "name": "processed_data",
            "type": "memory_store",
            "access": "read_write",
            "description": "Store for transformed data with validity flags"
          }
        ],
        "data_operations": [
          {
            "operation": "read",
            "target": "processed_data",
            "description": "Read processed data for validation"
          },
          {
            "operation": "write",
            "target": "processed_data",
            "description": "Update processed data with validity flags"
          }
        ]
      }
    },
    {
      "name": "ExportResults",
      "purpose": "Export only valid records from processed_data to output",
      "call_inputs": [
        {
          "name": "export_trigger",
          "description": "Signal to start export",
          "source": "parent input"
        }
      ],
      "call_outputs": [
        {
          "name": "output",
          "description": "JSON with success, records_processed, errors, data",
          "consumer": "parent"
        }
      ],
      "internal_leaf_accesses": [
        {
          "store": "processed_data",
          "access": "read",
          "description": "Read processed data to filter valid records"
        }
      ],
      "governance": {
        "execution_mode": "synchronous",
        "retry_policy": {
          "max_retries": 3,
          "backoff_seconds": 1
        },
        "timeout_seconds": 30,
        "logging_level": "info",
        "error_handling": "fail_fast"
      },
      "resources": {
        "global_vars": [
          {
            "name": "processed_data",
            "type": "memory_store",
            "access": "read",
            "description": "Store for transformed data with validity flags"
          }
        ],
        "data_operations": [
          {
            "operation": "read",
            "target": "processed_data",
            "description": "Read processed data to filter valid records"
          }
        ]
      }
    }
  ]
}
